(window.webpackJsonp=window.webpackJsonp||[]).push([[70],{542:function(t,e,n){"use strict";n.r(e);var r=n(0),o=Object(r.a)({},(function(){return this._self._c("ContentSlotsDistributor",{attrs:{"slot-key":this.$parent.slotKey}},[this._self._c("div",{domProps:{innerHTML:"<p>&lt;div class=&quot;custom-block tip&quot;&gt;&lt;p class=&quot;custom-block-title&quot;&gt;摘要&lt;/p&gt;\n机房环境监测是数字孪生项目的重要组成部分。本文介绍如何将 ECharts 图表与 Three.js 3D 场景结合，实现温度、湿度、电力等多维度数据的可视化展示，通过模块化设计构建高复用的环境监测组件体系。\n&lt;/div&gt;</p>\n<h2>一、环境监测需求</h2>\n<p>数字孪生机房需要实时展示以下环境数据：</p>\n<table>\n<thead>\n<tr>\n<th>监测维度</th>\n<th>数据来源</th>\n<th>展示形式</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>温度</td>\n<td>温湿度传感器</td>\n<td>温度计组件 + 热图</td>\n</tr>\n<tr>\n<td>湿度</td>\n<td>温湿度传感器</td>\n<td>圆形进度条</td>\n</tr>\n<tr>\n<td>电力</td>\n<td>智能电表</td>\n<td>柱状图 + 趋势线</td>\n</tr>\n<tr>\n<td>PUE</td>\n<td>计算值</td>\n<td>仪表盘</td>\n</tr>\n<tr>\n<td>空调状态</td>\n<td>BMS系统</td>\n<td>3D 模型状态</td>\n</tr>\n</tbody>\n</table>\n<h2>二、环境监测组件封装</h2>\n<h3>温度计组件</h3>\n<pre><code class=\"language-vue\">&lt;template&gt;\n  &lt;div class=&quot;thermometer-container&quot;&gt;\n    &lt;div ref=&quot;chartRef&quot; class=&quot;chart-area&quot;&gt;&lt;/div&gt;\n    &lt;div class=&quot;temp-value&quot;&gt;{{ temperature }}°C&lt;/div&gt;\n    &lt;div class=&quot;temp-label&quot;&gt;{{ label }}&lt;/div&gt;\n  &lt;/div&gt;\n&lt;/template&gt;\n\n&lt;script setup&gt;\nimport { ref, watch, onMounted, onBeforeUnmount } from 'vue'\nimport * as echarts from 'echarts'\n\nconst props = defineProps({\n  temperature: { type: Number, default: 0 },\n  label: { type: String, default: '' },\n  max: { type: Number, default: 50 },\n  thresholds: {\n    type: Object,\n    default: () =&gt; ({ warning: 35, danger: 42 })\n  }\n})\n\nconst chartRef = ref(null)\nlet chart = null\n\nfunction getColor(temp) {\n  if (temp &gt;= props.thresholds.danger) return '#ff4d4f'\n  if (temp &gt;= props.thresholds.warning) return '#faad14'\n  return '#52c41a'\n}\n\nfunction initChart() {\n  chart = echarts.init(chartRef.value)\n  updateChart()\n}\n\nfunction updateChart() {\n  const color = getColor(props.temperature)\n  chart.setOption({\n    series: [{\n      type: 'gauge',\n      center: ['50%', '60%'],\n      startAngle: 200,\n      endAngle: -20,\n      min: 0,\n      max: props.max,\n      itemStyle: { color },\n      progress: {\n        show: true,\n        width: 8\n      },\n      pointer: { show: false },\n      axisLine: {\n        lineStyle: { width: 8, color: [[1, '#304156']] }\n      },\n      axisTick: { show: false },\n      splitLine: { show: false },\n      axisLabel: { show: false },\n      detail: { show: false },\n      data: [{ value: props.temperature }]\n    }]\n  })\n}\n\nwatch(() =&gt; props.temperature, updateChart)\n\nonMounted(initChart)\nonBeforeUnmount(() =&gt; chart?.dispose())\n&lt;/script&gt;\n</code></pre>\n<h3>圆形进度条组件</h3>\n<pre><code class=\"language-vue\">&lt;template&gt;\n  &lt;div class=&quot;circle-progress&quot;&gt;\n    &lt;div ref=&quot;chartRef&quot; class=&quot;chart&quot;&gt;&lt;/div&gt;\n    &lt;div class=&quot;center-text&quot;&gt;\n      &lt;div class=&quot;value&quot;&gt;{{ value }}{{ unit }}&lt;/div&gt;\n      &lt;div class=&quot;label&quot;&gt;{{ label }}&lt;/div&gt;\n    &lt;/div&gt;\n  &lt;/div&gt;\n&lt;/template&gt;\n\n&lt;script setup&gt;\nimport { ref, watch, onMounted, onBeforeUnmount } from 'vue'\nimport * as echarts from 'echarts'\n\nconst props = defineProps({\n  value: Number,\n  max: { type: Number, default: 100 },\n  label: String,\n  unit: { type: String, default: '%' },\n  color: { type: String, default: '#1890ff' }\n})\n\nconst chartRef = ref(null)\nlet chart = null\n\nfunction updateChart() {\n  chart?.setOption({\n    series: [{\n      type: 'pie',\n      radius: ['75%', '90%'],\n      avoidLabelOverlap: false,\n      label: { show: false },\n      data: [\n        {\n          value: props.value,\n          itemStyle: {\n            color: new echarts.graphic.LinearGradient(0, 0, 0, 1, [\n              { offset: 0, color: props.color },\n              { offset: 1, color: `${props.color}88` }\n            ])\n          }\n        },\n        {\n          value: props.max - props.value,\n          itemStyle: { color: 'rgba(255,255,255,0.08)' }\n        }\n      ]\n    }]\n  })\n}\n\nwatch(() =&gt; props.value, updateChart)\nonMounted(() =&gt; {\n  chart = echarts.init(chartRef.value)\n  updateChart()\n})\nonBeforeUnmount(() =&gt; chart?.dispose())\n&lt;/script&gt;\n</code></pre>\n<h2>三、3D 场景中的环境可视化</h2>\n<h3>温度热图叠加</h3>\n<p>将温度数据映射为 3D 场景中的热图平面：</p>\n<pre><code class=\"language-javascript\">function updateEnvironmentVisualization(envData) {\n  // 更新热图\n  const heatmapCanvas = generateHeatmapFromSensors(envData.sensors)\n  heatmapPlane.material.map = new THREE.CanvasTexture(heatmapCanvas)\n  heatmapPlane.material.map.needsUpdate = true\n\n  // 更新空调模型状态\n  envData.airConditioners.forEach((ac) =&gt; {\n    const acModel = sceneManager.getDeviceMesh(ac.id)\n    if (!acModel) return\n\n    if (ac.running) {\n      // 运行中 - 添加风流粒子效果\n      startAirflowParticles(acModel, ac.windSpeed)\n      acModel.material.color.setHex(0x00aaff)\n    } else {\n      stopAirflowParticles(acModel)\n      acModel.material.color.setHex(0x666666)\n    }\n  })\n}\n</code></pre>\n<h3>空调风流粒子效果</h3>\n<pre><code class=\"language-javascript\">function createAirflowParticles(acPosition, direction) {\n  const particleCount = 200\n  const geometry = new THREE.BufferGeometry()\n  const positions = new Float32Array(particleCount * 3)\n  const velocities = []\n\n  for (let i = 0; i &lt; particleCount; i++) {\n    positions[i * 3] = acPosition.x + (Math.random() - 0.5) * 2\n    positions[i * 3 + 1] = acPosition.y + Math.random() * 3\n    positions[i * 3 + 2] = acPosition.z + (Math.random() - 0.5) * 2\n\n    velocities.push(new THREE.Vector3(\n      direction.x * (0.5 + Math.random() * 0.5),\n      -0.02,\n      direction.z * (0.5 + Math.random() * 0.5)\n    ))\n  }\n\n  geometry.setAttribute('position', new THREE.BufferAttribute(positions, 3))\n\n  const material = new THREE.PointsMaterial({\n    color: 0x88ccff,\n    size: 0.1,\n    transparent: true,\n    opacity: 0.4,\n    depthWrite: false\n  })\n\n  const particles = new THREE.Points(geometry, material)\n  particles.userData.velocities = velocities\n\n  return particles\n}\n</code></pre>\n<h2>四、数据刷新策略</h2>\n<p>环境数据不需要每帧更新，采用分层刷新策略：</p>\n<pre><code class=\"language-javascript\">// 温湿度 - 10秒刷新\nsetInterval(() =&gt; {\n  fetchEnvironmentData().then(updateEnvironmentVisualization)\n}, 10000)\n\n// 电力数据 - 30秒刷新\nsetInterval(() =&gt; {\n  fetchEnergyData().then(updateEnergyCharts)\n}, 30000)\n\n// 告警数据 - WebSocket 实时推送\nws.onmessage = (event) =&gt; {\n  const alarm = JSON.parse(event.data)\n  if (alarm.type === 'environment') {\n    handleEnvironmentAlarm(alarm)\n  }\n}\n</code></pre>\n<h2>五、总结</h2>\n<p>Three.js + ECharts 的组合在环境监测场景中非常强大：</p>\n<ul>\n<li><strong>ECharts</strong> 负责精确的数据图表展示</li>\n<li><strong>Three.js</strong> 负责空间化的环境状态可视化</li>\n<li>两者通过数据中心统一驱动，实现 <strong>多维度、多层次</strong> 的监测体验</li>\n<li>模块化的组件设计让温度计、进度条等组件可以在多个项目中复用</li>\n</ul>\n"}})])}),[],!1,null,null,null);e.default=o.exports}}]);